import { useEffect, useMemo, useState } from 'react';
import './App.css';

const COLUMNS = [
  { id: 'backlog', title: 'Backlog' },
  { id: 'todo', title: 'To Do' },
  { id: 'doing', title: 'In Progress' },
  { id: 'review', title: 'Review' },
  { id: 'done', title: 'Done' },
];

const FOUR_HOURS_MS = 4 * 60 * 60 * 1000;

const formatDue = (ms) => {
  if (!ms) return 'No update timer';
  const diff = ms - Date.now();
  if (diff <= 0) return 'Status update due now';
  const hrs = Math.floor(diff / (1000 * 60 * 60));
  const mins = Math.floor((diff % (1000 * 60 * 60)) / (1000 * 60));
  return `Next update in ${hrs}h ${mins}m`;
};

function App() {
  const [tasks, setTasks] = useState([]);
  const [title, setTitle] = useState('');
  const [notes, setNotes] = useState('');
  const [owner, setOwner] = useState('Both');

  const [editingTaskId, setEditingTaskId] = useState(null);
  const [editTitle, setEditTitle] = useState('');
  const [editNotes, setEditNotes] = useState('');
  const [editOwner, setEditOwner] = useState('Both');

  const [updateInputs, setUpdateInputs] = useState({});

  const persistTasks = async (nextTasks) => {
    setTasks(nextTasks);
    await fetch('/api/tasks', {
      method: 'PUT',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify(nextTasks),
    });
  };

  useEffect(() => {
    fetch('/api/tasks')
      .then((r) => r.json())
      .then((data) => setTasks(Array.isArray(data) ? data : []))
      .catch(() => setTasks([]));
  }, []);

  const counts = useMemo(
    () =>
      COLUMNS.reduce((acc, col) => {
        acc[col.id] = tasks.filter((t) => t.status === col.id).length;
        return acc;
      }, {}),
    [tasks]
  );

  const addTask = async (e) => {
    e.preventDefault();
    if (!title.trim()) return;

    const newTask = {
      id: crypto.randomUUID(),
      title: title.trim(),
      notes: notes.trim(),
      owner,
      status: 'backlog',
      createdAt: Date.now(),
      updates: [],
    };

    await persistTasks([newTask, ...tasks]);
    setTitle('');
    setNotes('');
    setOwner('Both');
  };

  const moveTask = async (taskId, newStatus) => {
    const next = tasks.map((task) =>
      task.id === taskId ? { ...task, status: newStatus } : task
    );
    await persistTasks(next);
  };

  const removeTask = async (taskId) => {
    const next = tasks.filter((task) => task.id !== taskId);
    await persistTasks(next);
    if (editingTaskId === taskId) setEditingTaskId(null);
  };

  const startEditing = (task) => {
    setEditingTaskId(task.id);
    setEditTitle(task.title);
    setEditNotes(task.notes || '');
    setEditOwner(task.owner || 'Both');
  };

  const cancelEditing = () => {
    setEditingTaskId(null);
    setEditTitle('');
    setEditNotes('');
    setEditOwner('Both');
  };

  const saveEdit = async (taskId) => {
    if (!editTitle.trim()) return;
    const next = tasks.map((task) =>
      task.id === taskId
        ? {
            ...task,
            title: editTitle.trim(),
            notes: editNotes.trim(),
            owner: editOwner,
          }
        : task
    );
    await persistTasks(next);
    cancelEditing();
  };

  const addUpdate = async (taskId) => {
    const text = (updateInputs[taskId]?.text || '').trim();
    const author = updateInputs[taskId]?.author || 'TheAIos';
    if (!text) return;

    const next = tasks.map((task) => {
      if (task.id !== taskId) return task;
      const updates = Array.isArray(task.updates) ? task.updates : [];
      const entry = {
        id: crypto.randomUUID(),
        text,
        author,
        createdAt: Date.now(),
      };

      return {
        ...task,
        updates: [entry, ...updates],
        nextUpdateDueAt: task.status === 'doing' ? Date.now() + FOUR_HOURS_MS : task.nextUpdateDueAt,
      };
    });

    await persistTasks(next);
    setUpdateInputs((prev) => ({
      ...prev,
      [taskId]: { text: '', author },
    }));
  };

  return (
    <div className="app-shell">
      <header className="topbar">
        <h1>My Life Board</h1>
        <p>Shared Kanban for Joseph + TheAIos</p>
      </header>

      <section className="composer-card">
        <form onSubmit={addTask} className="composer-form">
          <input value={title} onChange={(e) => setTitle(e.target.value)} placeholder="Add a task..." />
          <input value={notes} onChange={(e) => setNotes(e.target.value)} placeholder="Optional details" />
          <select value={owner} onChange={(e) => setOwner(e.target.value)}>
            <option>Both</option>
            <option>Joseph</option>
            <option>TheAIos</option>
          </select>
          <button type="submit">Add</button>
        </form>
      </section>

      <main className="board">
        {COLUMNS.map((column) => (
          <section
            key={column.id}
            className="column"
            onDragOver={(e) => e.preventDefault()}
            onDrop={(e) => {
              const taskId = e.dataTransfer.getData('text/plain');
              if (taskId) moveTask(taskId, column.id);
            }}
          >
            <div className="column-head">
              <h2>{column.title}</h2>
              <span>{counts[column.id] || 0}</span>
            </div>

            <div className="column-body">
              {tasks
                .filter((task) => task.status === column.id)
                .map((task) => {
                  const isEditing = editingTaskId === task.id;
                  const updates = Array.isArray(task.updates) ? task.updates : [];

                  return (
                    <article
                      key={task.id}
                      className="task"
                      draggable={!isEditing}
                      onDragStart={(e) => e.dataTransfer.setData('text/plain', task.id)}
                    >
                      {isEditing ? (
                        <div className="task-edit">
                          <input value={editTitle} onChange={(e) => setEditTitle(e.target.value)} />
                          <input value={editNotes} onChange={(e) => setEditNotes(e.target.value)} />
                          <select value={editOwner} onChange={(e) => setEditOwner(e.target.value)}>
                            <option>Both</option>
                            <option>Joseph</option>
                            <option>TheAIos</option>
                          </select>
                          <div className="task-actions">
                            <button className="action-btn save" onClick={() => saveEdit(task.id)}>Save</button>
                            <button className="action-btn" onClick={cancelEditing}>Cancel</button>
                          </div>
                        </div>
                      ) : (
                        <>
                          <div className="task-title">{task.title}</div>
                          {task.notes ? <p>{task.notes}</p> : null}

                          {task.status === 'doing' && task.owner === 'TheAIos' ? (
                            <div className={`due-pill ${task.nextUpdateDueAt && task.nextUpdateDueAt <= Date.now() ? 'due-now' : ''}`}>
                              {formatDue(task.nextUpdateDueAt)}
                            </div>
                          ) : null}

                          <details className="updates-panel">
                            <summary>Comments / Status ({updates.length})</summary>
                            <div className="updates-body">
                              <div className="update-input-row">
                                <input
                                  placeholder="Add status or comment..."
                                  value={updateInputs[task.id]?.text || ''}
                                  onChange={(e) =>
                                    setUpdateInputs((prev) => ({
                                      ...prev,
                                      [task.id]: {
                                        text: e.target.value,
                                        author: prev[task.id]?.author || 'TheAIos',
                                      },
                                    }))
                                  }
                                />
                                <select
                                  value={updateInputs[task.id]?.author || 'TheAIos'}
                                  onChange={(e) =>
                                    setUpdateInputs((prev) => ({
                                      ...prev,
                                      [task.id]: {
                                        text: prev[task.id]?.text || '',
                                        author: e.target.value,
                                      },
                                    }))
                                  }
                                >
                                  <option>TheAIos</option>
                                  <option>Joseph</option>
                                  <option>Both</option>
                                </select>
                                <button className="action-btn" onClick={() => addUpdate(task.id)}>Post</button>
                              </div>

                              {updates.length === 0 ? (
                                <div className="empty-updates">No updates yet.</div>
                              ) : (
                                <ul className="updates-list">
                                  {updates.map((u) => (
                                    <li key={u.id}>
                                      <div className="update-meta">
                                        <strong>{u.author}</strong> · {new Date(u.createdAt).toLocaleString()}
                                      </div>
                                      <div>{u.text}</div>
                                    </li>
                                  ))}
                                </ul>
                              )}
                            </div>
                          </details>

                          <div className="task-footer">
                            <span className="pill">{task.owner}</span>
                            <div className="task-actions">
                              <button className="action-btn" onClick={() => startEditing(task)}>Edit</button>
                              <button className="action-btn delete" onClick={() => removeTask(task.id)}>Delete</button>
                            </div>
                          </div>
                        </>
                      )}
                    </article>
                  );
                })}
            </div>
          </section>
        ))}
      </main>
    </div>
  );
}

export default App;
